SELECT COUNT(*)
FROM EVENTLOG


        eventType = #{eventType}


        AND createTime >= #{searchDto.startDate}


        AND createTime <= #{searchDto.endDate}

SELECT robotId, eventType, message, note, status, createTime
FROM EVENTLOG


        eventType = #{eventType}


        AND createTime >= #{searchDto.startDate}


        AND createTime <= #{searchDto.endDate}


ORDER BY createTime DESC
LIMIT #{searchDto.pageSize}
OFFSET #{searchDto.offset}
